const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
const imageKey = binaryKeys.includes('image') ? 'image' : binaryKeys[0];
const image = imageKey ? item.binary[imageKey] : null;
if (!image?.data) {
  throw new Error('未收到圖片檔案。HTML FormData 欄位請命名為 image。');
}

const body = item.json || {};
const operatorRaw = body.operator || body.operatorJson || '{}';
let operator = {};
try {
  operator = typeof operatorRaw === 'string' ? JSON.parse(operatorRaw) : operatorRaw;
} catch (error) {
  operator = {};
}

const prompt = `你是製造業「現場補料單」OCR 與資料結構化助手。請辨識圖片中的單據資料，嚴格以 JSON 格式輸出，不要輸出 markdown 標記（如 \`\`\`json），也不要加上任何解釋文字。

【一、資料擷取核心邏輯】
1. 全局預判：請先掃描圖片中的表格，確認共有幾列明細，並將數字填入 total_detected_rows。
2. 換列判定：只要有獨立的「品號」、「規格」或「數量」出現，即視為獨立的一筆明細，必須與上下列分開。
3. 絕對完整性：看見幾列就必須輸出幾個 items。若某列字跡模糊或資料缺失，仍須保留該列，將無法辨識的欄位填入空字串或 0，並於 note 註明「字跡模糊無法判讀」。不可擅自忽略或整併正常資料。
4. 空白列排除：表格下方只有 #N/A 或完全空白且沒有品號、規格、數量的列，不算明細，不要輸出。

【二、欄位業務規則】
1. 共通資訊：表頭的「日期」請統一套用至所有 items。若每列製令單號相同，order_no 填主要製令單號；每列仍需在 work_order_no 填入該列製令單號。
2. 日期：若圖片為民國年，例如 115/2/13，請轉成西元 2026-02-13T00:00:00+08:00。無法判讀則輸出空字串。
3. 品號 part_no：
   - 第一個字元必須是英文大寫 A-Z。
   - 優先進行 OCR 誤讀校正：首碼若為 0 修正為 O；1 修正為 I；5 修正為 S；8 修正為 B。
   - 若校正後仍無法確認首碼為英文，請輸出空字串，並在 note 寫明「品號開頭非英文或無法確認」。
4. 規格 spec：包含尺寸、材質、百分比、中文描述或特殊符號，請完整保留原始文字，勿翻譯、勿截斷、勿合併相鄰列。
5. 數量欄位：只輸出數字；無法判讀時輸出 0。手寫數字若位於「實領數量」欄，請判斷為 received_qty；不要把勾勾、分數註記或括號當作規格。
6. 備註欄：請保留該列備註；沒有問題則填 OK。

【三、輸出 JSON 結構】
請嚴格遵守以下格式，確保可被 JSON.parse() 解析：
{
  "total_detected_rows": 0,
  "order_no": "製令單號或單據號碼，無法判讀則空字串",
  "date": "YYYY-MM-DDTHH:mm:ss+08:00，無法判讀則空字串",
  "items": [
    {
      "row_no": 1,
      "work_order_no": "該列製令單號；若只有表頭製令單號，請填表頭值；無法判讀則空字串",
      "part_no": "首碼必為英文，無法確認則空字串",
      "spec": "完整規格描述，無法判讀則空字串",
      "defective_qty": 0,
      "request_qty": 0,
      "received_qty": 0,
      "note": "備註、異常原因；沒有問題則填 OK"
    }
  ]
}`;

return [{
  json: {
    operator,
    imageMeta: {
      fileName: image.fileName || '',
      mimeType: image.mimeType || 'image/jpeg',
      fileSize: image.fileSize || ''
    },
    prompt
  },
  binary: {
    image
  }
}];

const NOTION_TOKEN = $env.NOTION_TOKEN;
const MASTER_DB = '33eb3ad1d1cd80fc9674e730c3c87469';
const RESULT_DB = '2f6b3ad1d1cd8068a597e0994b74654c';
const BATCH_DB = '374b3ad1d1cd80eeb5dff6b5991e1d29';

if (!NOTION_TOKEN) throw new Error('缺少環境變數 NOTION_TOKEN');

const requestMeta = $('準備 Gemini 請求').first().json;
const operator = requestMeta.operator || {};
const imageMeta = requestMeta.imageMeta || {};
const startedAt = new Date();
const batchId = `OCR-${startedAt.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}`;

const notionHeaders = {
  Authorization: `Bearer ${NOTION_TOKEN}`,
  'Notion-Version': '2022-06-28',
  'Content-Type': 'application/json'
};

function richText(value) {
  const text = String(value ?? '').slice(0, 1900);
  return text ? [{ type: 'text', text: { content: text } }] : [];
}

function title(value) {
  return [{ type: 'text', text: { content: String(value || '未判讀').slice(0, 1900) } }];
}

function num(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function normalize(value) {
  return String(value || '')
    .toUpperCase()
    .replace(/\s+/g, '')
    .replace(/[，,。.;；:：()（）\[\]【】"'「」]/g, '')
    .trim();
}

function isValidPartNo(value) {
  return /^[A-Za-z]/.test(String(value || '').trim());
}

function extractText(prop) {
  if (!prop) return '';
  if (prop.title) return prop.title.map((x) => x.plain_text || '').join('');
  if (prop.rich_text) return prop.rich_text.map((x) => x.plain_text || '').join('');
  if (prop.select) return prop.select.name || '';
  if (prop.number !== undefined) return String(prop.number ?? '');
  return '';
}

function safeDate(value) {
  const text = String(value || '').trim();
  if (!text) return null;
  const date = new Date(text);
  return Number.isNaN(date.getTime()) ? null : text;
}

function getGeminiText(payload) {
  for (const key of ['text', 'output', 'content', 'response', 'result', 'completion']) {
    if (typeof payload[key] === 'string' && payload[key].trim()) return payload[key].trim();
  }
  if (typeof payload.message?.content === 'string') return payload.message.content.trim();
  if (typeof payload.data === 'string') return payload.data.trim();
  const text = payload.candidates?.[0]?.content?.parts?.find((part) => typeof part.text === 'string')?.text || '';
  return text.trim();
}

function fallbackOcr(reason) {
  return {
    order_no: '',
    date: '',
    items: [{
      work_order_no: '',
      part_no: '',
      spec: '',
      defective_qty: 0,
      request_qty: 0,
      received_qty: 0,
      note: reason
    }]
  };
}

function parseOcr(payload) {
  const rawText = getGeminiText(payload);
  if (!rawText) return fallbackOcr('Gemini 未回傳文字內容');
  try {
    return JSON.parse(rawText);
  } catch (error) {
    const cleaned = rawText.replace(/^```json/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
    try {
      return JSON.parse(cleaned);
    } catch (innerError) {
      const match = rawText.match(/\{[\s\S]*\}/);
      if (!match) return fallbackOcr('Gemini 回傳非 JSON');
      try {
        return JSON.parse(match[0]);
      } catch (lastError) {
        return fallbackOcr('Gemini JSON 解析失敗');
      }
    }
  }
}

async function notionRequest(method, url, body) {
  const response = await fetch(url, {
    method,
    headers: notionHeaders,
    body: body ? JSON.stringify(body) : undefined
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(`Notion API ${response.status}: ${JSON.stringify(data)}`);
  }
  return data;
}

async function queryAllMasterPages() {
  const results = [];
  let start_cursor;
  do {
    const body = { page_size: 100 };
    if (start_cursor) body.start_cursor = start_cursor;
    const data = await notionRequest('POST', `https://api.notion.com/v1/databases/${MASTER_DB}/query`, body);
    results.push(...(data.results || []));
    start_cursor = data.has_more ? data.next_cursor : undefined;
  } while (start_cursor);
  return results;
}

async function createBatch(summary) {
  const now = new Date().toISOString();
  return notionRequest('POST', 'https://api.notion.com/v1/pages', {
    parent: { database_id: BATCH_DB },
    properties: {
      '名稱': { title: title(batchId) },
      '批次ID': { rich_text: richText(batchId) },
      '操作人': { rich_text: richText(operator.name || operator.displayName || '') },
      'LINE userId': { rich_text: richText(operator.userId || '') },
      '來源': { select: { name: 'HTML' } },
      '上傳時間': { date: { start: now } },
      '完成時間': { date: { start: now } },
      '狀態': { select: { name: '已寫入' } },
      '製令單號': { rich_text: richText(summary.order_no || '') },
      '總筆數': { number: summary.total },
      '通過筆數': { number: summary.passed },
      '異常筆數': { number: summary.abnormal },
      '人工修正筆數': { number: 0 },
      '圖片檔名': { rich_text: richText(imageMeta.fileName || '') },
      '圖片資訊': { rich_text: richText(`${imageMeta.mimeType || ''} ${imageMeta.fileSize || ''}`.trim()) }
    }
  });
}

async function createResultPage(row, batchUrl) {
  const date = safeDate(row.date);
  const properties = {
    '製令單號': { title: title(row.work_order_no || row.order_no || '未判讀') },
    '製令單號check': { checkbox: row.orderNoCheck },
    '日期': date ? { date: { start: date } } : { date: null },
    '品號': { rich_text: richText(row.partNo) },
    '品號check': { checkbox: row.partNoCheck },
    '規格': { rich_text: richText(row.spec) },
    '規格check': { checkbox: row.specCheck },
    '不良數量': { number: num(row.defectiveQty) },
    '需領數量': { number: num(row.requestQty) },
    '實領數量': { number: num(row.receivedQty) },
    '備註': { rich_text: richText(row.note) },
    '批次ID': { rich_text: richText(batchId) },
    '操作人': { rich_text: richText(operator.name || operator.displayName || '') },
    'LINE userId': { rich_text: richText(operator.userId || '') },
    '原始品號': { rich_text: richText(row.partNo) },
    '原始規格': { rich_text: richText(row.spec) },
    '是否人工修正': { checkbox: false },
    '比對結果': { select: { name: row.status } },
    'OCR狀態': { select: { name: row.ocrStatus } },
    '主檔規格': { rich_text: richText(row.masterSpec) },
    '異常原因': { rich_text: richText(row.note) },
    'Notion批次URL': batchUrl ? { url: batchUrl } : { url: null }
  };

  return notionRequest('POST', 'https://api.notion.com/v1/pages', {
    parent: { database_id: RESULT_DB },
    properties
  });
}

const ocr = parseOcr($json);
let items = Array.isArray(ocr.items) ? ocr.items : [];
items = items.filter((item) => {
  const partNo = String(item.part_no || '').trim();
  const spec = String(item.spec || '').trim();
  return partNo || spec || item.note;
});
if (!items.length) {
  items = fallbackOcr('OCR 沒有有效明細列').items;
}

const masterPages = await queryAllMasterPages();
const masterMap = new Map();
for (const page of masterPages) {
  const partNo = extractText(page.properties?.['品號']).trim();
  if (partNo) masterMap.set(normalize(partNo), page);
}

const rows = items.map((item) => {
  const partNo = String(item.part_no || '').trim();
  const spec = String(item.spec || '').trim();
  const workOrderNo = String(item.work_order_no || ocr.order_no || '').trim();
  const master = masterMap.get(normalize(partNo));
  const masterSpec = extractText(master?.properties?.['規格']);
  const orderNoCheck = Boolean(workOrderNo && workOrderNo !== '未判讀');
  const partNoStartsOk = isValidPartNo(partNo);
  const partNoCheck = Boolean(partNoStartsOk && master);
  const specCheck = Boolean(master && normalize(masterSpec) && normalize(spec) && normalize(masterSpec) === normalize(spec));
  const notes = [];
  if (!orderNoCheck) notes.push('製令單號未判讀');
  if (!partNo) notes.push('品號未判讀');
  if (partNo && !partNoStartsOk) notes.push('品號開頭非英文');
  if (partNoStartsOk && !master) notes.push('主檔查無品號');
  if (!spec) notes.push('規格未判讀');
  if (master && !specCheck) notes.push(`規格不符；主檔：${masterSpec || '空值'}`);
  if (item.note) notes.push(String(item.note));
  const status = orderNoCheck && partNoCheck && specCheck ? 'OK' : '異常';
  const ocrStatus = partNo && spec ? '辨識完成' : '辨識不完整';
  return {
    status,
    ocrStatus,
    order_no: ocr.order_no || '',
    work_order_no: workOrderNo,
    date: ocr.date || '',
    partNo,
    spec,
    masterSpec,
    defectiveQty: num(item.defective_qty),
    requestQty: num(item.request_qty),
    receivedQty: num(item.received_qty),
    orderNoCheck,
    partNoCheck,
    specCheck,
    note: notes.join('；') || 'OK'
  };
});

const total = rows.length;
const abnormal = rows.filter((row) => row.status !== 'OK').length;
const summary = {
  order_no: ocr.order_no || rows[0]?.work_order_no || '',
  date: ocr.date || '',
  total,
  passed: total - abnormal,
  abnormal
};

const batchPage = await createBatch(summary);
const createdPages = [];
for (const row of rows) {
  const page = await createResultPage(row, batchPage.url);
  createdPages.push(page);
}

return [{
  json: {
    ok: true,
    batchId,
    order_no: summary.order_no,
    date: summary.date,
    total: summary.total,
    passed: summary.passed,
    abnormal: summary.abnormal,
    first_notion_url: createdPages[0]?.url || batchPage.url || '',
    batch_notion_url: batchPage.url || '',
    results: rows.map((row, index) => ({
      status: row.status,
      partNo: row.partNo,
      spec: row.spec,
      defectiveQty: row.defectiveQty,
      requestQty: row.requestQty,
      receivedQty: row.receivedQty,
      note: row.note,
      notionUrl: createdPages[index]?.url || ''
    }))
  }
}];
